Print('update TransactionTypes')
go
Update [CRE].[TransactionTypes] set [AccountName] = TransactionName
update  [CRE].[TransactionTypes] set AccountName ='periodint' where TransactionName ='InterestPaid'
update  [CRE].[TransactionTypes] set AccountName ='periodpikint' where TransactionName ='PIKInterest'
update  [CRE].[TransactionTypes] set AccountName ='periodpikintpaid' where TransactionName ='PIKInterestPaid'
update  [CRE].[TransactionTypes] set AccountName ='pikprinpaid' where TransactionName ='PIKPrincipalPaid'
go


