INSERT [CRE].[JsonTemplate] ([Id], [Key], [Value], [Type], [FileName], [JsonTemplateMasterID]) VALUES (3, N'rules', N'[{"description":"Attach a rule which should be executed when an account is updated","type":"attach_rules_to_accounts","config":{"funding":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''ACORE Orig Fee'', ''Origination Fee_AsFunded'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"paydown":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee'', ''Exit Fee_IncAmor'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[-@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"schprin":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee_IncAmor'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"balloon":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee'', ''Exit Fee_IncAmor'', ''Exit Fee_Payoff'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"fee_stripped":[{"description":"Add Fee stripping included in level yield transaction","type":"add_cashflow","condition":"(@amount != 0)","config":{"Date":"@date","Note":"@note.id","type":"@fee_type.replace('' '', '''') + ''Stripping''","expression":"-@amount * @fee.levyldincl","addl_columns":{"Fee Name":"@fee_name"}}},{"description":"Add Fee stripping excluded from level yield transaction","type":"add_cashflow","condition":"(@amount != 0)","config":{"Date":"@date","Note":"@note.id","type":"@fee_type.replace('' '', '''') + ''StrippingExcldfromLevelYield''","expression":"-@amount * (1 - @fee.levyldincl)","addl_columns":{"Fee Name":"@fee_name"}}},{"description":"Calculate Fee Stripping","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee_stripping'']))","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_stripping","rules":[{"description":"Add StripReceivable transactions","type":"add_cashflow","config":{"Date":"@date","Note":"@strip.to","type":"@fee_type","expression":"@amount * @strip.pct","addl_columns":{"Fee Name":"@fee_name","Effective Date":"@effective_date","Parent Note":"@root_note_id"}}}]}}],"pmtdtpikint":[{"description":"Update balances if pik interest for prior day is updated","type":"foreach","condition":"(@amount != 0) & @update_balances & (@row[''Date''] < @row[''periodend''])","config":{"foreach_variable_name":"date","expression":"pd.date_range(@row[''Date''], @row[''periodend''], closed=''left'')","rules":[{"description":"Update ending balance","type":"accumulate","config":{"filter":"@df.Date == @date","columns":["endbal"],"expression":"@amount"}},{"description":"Update next day''s beginning balance","type":"accumulate","config":{"filter":"@df.Date == (pd.Timestamp(@date) + pd.DateOffset())","columns":["initbal"],"expression":"@amount"}}]}}]}},{"description":"For each effective date, execute the following rules","type":"foreach","config":{"foreach_variable_name":"effective_date","expression":"[x for x in @effective_dates if pd.Timestamp(x) <= pd.Timestamp(@period_end_date)]","rules":[{"description":"Setup context for effective date","context":[{"name":"note","expression":"@notes[@root_note_id]"},{"name":"is_legal_note","expression":"@note.type == ''legal''"},{"name":"is_closed_note","expression":"@if_exists(@note, [@effective_date], [])"},{"name":"is_closing_effective_date","expression":"@is_closed_note & (pd.Timestamp(@note[@effective_date].clsdt) == pd.Timestamp(@effective_date))"},{"name":"loop_until","expression":"@next_effective_date if not @calc_basis and @next_effective_date else @period_end_date"},{"name":"dates_in_current_schedule","expression":"pd.date_range(@effective_date, @loop_until)"},{"name":"date_filter","expression":"@df.Date.isin(@dates_in_current_schedule)"},{"name":"loanterm","expression":"(pd.Timestamp(@note[@effective_date].initmatdt).year - pd.Timestamp(@note[@effective_date].clsdt).year)*12 + (pd.Timestamp(@note[@effective_date].initmatdt).month - pd.Timestamp(@note[@effective_date].clsdt).month)"},{"name":"update_balances","value":false}]},{"description":"Delete data for dates greater than effective date","type":"reset","config":{"df":"@df.Date >= pd.Timestamp(@effective_date)","cf":"(@cf.Date >= pd.Timestamp(@effective_date)) & (@cf.Note == @root_note_id)"}},{"description":"Set the Effective Date Column","type":"assignment","condition":"@is_closed_note","config":{"filter":"(@date_filter)","columns":["effectivedate"],"expression":"@effective_date"}},{"description":"Set the Loan Term based on Current Maturity","type":"assignment","condition":"@is_closed_note","config":{"filter":"(@date_filter)","columns":["loanterm"],"expression":"(pd.Timestamp(@note[@effective_date].initmatdt).year - pd.Timestamp(@note[@effective_date].clsdt).year)*12 + (pd.Timestamp(@note[@effective_date].initmatdt).month - pd.Timestamp(@note[@effective_date].clsdt).month)"}},{"description":"Add Initial Funding transaction","type":"add_cashflow","condition":"@is_closing_effective_date","config":{"Date":"pd.Timestamp(@note[@effective_date].clsdt)","Note":"@note.id","type":"InitialFunding","expression":"-@note[@effective_date].initbal"}},{"description":"Read v