,"parameters":["@df.Date","pd.to_datetime(@df.initaccenddt).dt.day","@df.dayofmnth"]}}},{"description":"Calculate Drop Date Addon","type":"assignment","config":{"columns":["ddbaladdon"],"expression":"@df.funding.astype(''float64'') + @df.paydown.astype(''float64'')"}},{"description":"Calculate Drop Date Addon","type":"assignment","config":{"filter":"@df.is_dropperiod","columns":["ddbaladdon"],"expression":"@df.groupby([''Note'', ''term'']).ddbaladdon.cumsum().apply(str).apply(Decimal)"}},{"description":"Calculate Drop Date Interest Delta","type":"assignment","config":{"filter":"@df.is_dropperiod","columns":["ddintdelta"],"function":{"name":"daily_accrued_interest","module":"coupon","package":"m61_finance.cre","parameters":["@df.ddbaladdon","@df.allincouponrate","@df.allinadjfactor"]}}},{"description":"Calculate Cumulative Drop Date Interest Delta - Convert to Float","type":"assignment","config":{"columns":["float_ddintdelta"],"expression":"@df.ddintdelta.astype(''float64'')"}},{"description":"Calculate Cumulative Drop Date Interest Delta","type":"assignment","config":{"columns":["cum_ddintdelta"],"expression":"@df.groupby([''Note'', ''term'']).float_ddintdelta.cumsum().apply(str).apply(Decimal)"}},{"description":"Calculate Accrual Period Interest Delta","type":"assignment","config":{"filter":"(@df.Date == @df.periodend)","columns":["periodddintdelta"],"expression":"@df.cum_ddintdelta.shift(fill_value=Decimal(0))"}},{"description":"Calculate Accrual Period Interest Delta - Final Period or Soft Pay Off","type":"assignment","config":{"filter":"(@df.periodstart <= @df.initmatdt) & (@df.initmatdt <= @df.periodend)","columns":["periodddintdelta"],"expression":"@df.periodddintdelta + @df.cum_ddintdelta"}},{"description":"Calculate Accrual Period Interest for periods with actuals","type":"assignment","config":{"filter":"(@date_filter) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.act_periodint > 0)","columns":["periodint"],"expression":"@df.act_periodint"}},{"description":"Calculate Accrual Period Interest for periods without actuals","type":"assignment","config":{"filter":"(@date_filter) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.act_periodint == 0)","columns":["periodint"],"expression":"@df.cum_dailyint"}},{"description":"Calculate Accrual Period Interest for periods without actuals - with Drop Date","type":"assignment","context":[{"name":"last_period_with_actuals","expression":"max([pd.Timestamp(x.dt) for x in @note[@effective_date].get(''actuals'', [])], default=@df.Date[0] - pd.DateOffset())"}],"config":{"filter":"(@date_filter) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.Date > @last_period_with_actuals)","columns":["ddperiodint"],"expression":"@df.periodint - @df.period_ddintdelta_shifted"}},{"description":"For each fee, process below rules","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''fee''])","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in @config.fee.config and ''accounts'' in @config.fee.config[x.type]]","rules":[{"description":"For each account, calculate fee","type":"foreach","config":{"foreach_variable_name":"account","expression":"@config.fee.config[@fee.type].accounts","rules":[{"description":"Calculate Fee","type":"accumulate","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"},{"name":"fee_filter","expression":"(@df.Date == pd.Timestamp(@fee.startdt)) & (pd.Timestamp(@effective_date) <= pd.Timestamp(@fee.startdt))"}],"config":{"filter":"(@date_filter) & (@fee_filter) & (@df[@account] != 0)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["@df[@account]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}]}},{"description":"Apply true up on maturity date","type":"foreach","condition":"(pd.Timestamp(@note[@effective_date].initmatdt) <= pd.Timestamp(@loop_until)) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if (x.ovrfeeamt == 0) & (x.ovrbaseamt != 0) & (x.trueupflag == ''571'') & (pd.Timestamp(x.startdt) <= pd.Timestamp(@note[@effective_date].initmatdt) <= pd.Timestamp(x.enddt))]","rules":[{"description":"Calculate Fee for maturity date","type":"accumulate","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"},{"name":"total_paydowns","expression":"@df.paydown.sum()"}],"config":{"filter":"(@df.Date == @df.initmatdt)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["@fee.ovrbaseamt + @total_paydowns - @df.balloon",null,null,"@fee.val","@fee.stripval","@fee.levyldincl",false]}}}]}},{"description":"Calculate Gross Deferred Fee for the Effective Date","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["gross_def_fees"],"expression":"@df.fee_incl_lv_yield.sum()"}},{"description":"Calculate Clean Cost","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["clean_cost"],"expression":"@df.endbal - @df.gross_def_fees + @df.discount  + @df.capcosts"}},{"description":"For each note, execute the basis rules","type":"foreach","condition":"@calc_basis","config":{"foreach_variable_name":"note","expression":"@notes.values()","rules":[{"description":"Calculate Level Yield - Deferred Fee Yield","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''gaapbasis'']"}],"config":{"filter":"(@date_filter)","columns":["levyld"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal - @df.endbal + @df.fee_incl_lv_yield","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Level Yield - Copy to deffeeyld","type":"assignment","config":{"filter":"(@date_filter) & (@df.Date == @df.effectivedate)","columns":["deffeeyld"],"expression":"@df.levyld"}},{"description":"Calculate Gaap Basis - Deferred Fee Basis","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","context":[{"name":"yld","expression":"@df[@df.Date==@effective_date].deffeeyld[0]"}],"config":{"filter":"(@date_filter)","columns":["gaapbasis"],"function":{"name":"calculate_gaapbasis","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal","@df.fee_incl_lv_yield","@yld"]}}},{"description":"Calculate Fee Amort","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@date_filter)","columns":["feeamort"],"function":{"name":"calculate_feeamort","module":"basis","package":"m61_finance.cre","parameters":["@df.initbal-@df.endbal","@df.fee_incl_lv_yield","@df.gaapbasis"]}}},{"description":"Calculate Cumulative Amort(Def Fee) - Convert to Float","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@date_filter)","columns":["float_am_fee"],"expression":"@df.feeamort.astype(''float64'')"}},{"description":"Calculate Cumulative Amort (Def Fee)","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","config":{"filter":"(@date_filter)","columns":["cum_am_fee"],"expression":"@df.float_am_fee.cumsum().apply(str).apply(Decimal)"}},{"description":"Calculate Level Yield - Discount/Prmium Yield","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''bas_disc'']"}],"config":{"filter":"(@date_filter)","columns":["yld_disc"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal+@df.discount","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Gaap Basis - Discout/Premium Basis","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@date_filter)","columns":["bas_disc"],"function":{"name":"calculate_gaapbasis","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal","@df.discount","@df.yld_disc[0]"]}}},{"description":"Calculate Fee Amort","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@date_filter)","columns":["am_disc"],"function":{"name":"calculate_feeamort","module":"basis","package":"m61_finance.cre","parameters":["@df.initbal-@df.endbal","@df.discount","@df.bas_disc"]}}},{"description":"Calculate Cumulative Amort(Discount) - Convert to Float","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@date_filter)","columns":["float_am_disc"],"expression":"@df.am_disc.astype(''float64'')"}},{"description":"Calculate Cumulative Amort (Discout)","type":"assignment","condition":"(@calc_disc_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''discount''])))","config":{"filter":"(@date_filter)","columns":["cum_am_disc"],"expression":"@df.float_am_disc.cumsum().apply(str).apply(Decimal)"}},{"description":"Calculate Level Yield - Capitalized Costs","type":"assignment","condition":"(@calc_capcosts_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''capcosts''])))","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''bas_capcosts'']"}],"config":{"filter":"(@date_filter)","columns":["yld_capcosts"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal+@df.capcosts","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Gaap Basis - Capitalized Closing Costs","type":"assignment","condition":"(@calc_capcosts_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''capcosts''])))","config":{"filter":"(@date_filter)","columns":["bas_capcosts"],"function":{"name":"calculate_gaapbasis","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal-@df.endbal","@df.capcosts","@df.yld_capcosts[0]"]}}},{"description":"Calculate Cap Costs Amort","type":"assignment","condition":"(@calc_capcosts_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''capcosts''])))","config":{"filter":"(@date_filter)","columns":["am_capcosts"],"function":{"name":"calculate_feeamort","module":"basis","package":"m61_finance.cre","parameters":["@df.initbal-@df.endbal","@df.capcosts","@df.bas_capcosts"]}}},{"description":"Calculate Cumulative Amort(Cap Costs) - Convert to Float","type":"assignment","condition":"(@calc_capcosts_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''capcosts''])))","config":{"filter":"(@date_filter)","columns":["float_am_capcosts"],"expression":"@df.am_capcosts.astype(''float64'')"}},{"description":"Calculate Cumulative Amort (Cap Costs)","type":"assignment","condition":"(@calc_capcosts_basis & @is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_dates[0]], [''capcosts''])))","config":{"filter":"(@date_filter)","columns":["cum_am_capcosts"],"expression":"@df.float_am_capcosts.cumsum().apply(str).apply(Decimal)"}},{"description":"Calculate GAAP BV","type":"assignment","config":{"filter":"(@date_filter)","columns":["gaapbv"],"function":{"name":"calculate_gaapbv","module":"basis","package":"m61_finance.cre","parameters":["@df.clean_cost","@df.cum_dailyint","@df.cum_dailypikint","@df.cum_am_fee","@df.cum_am_disc","@df.cum_am_capcosts"]}}}]}}]}},{"description":"Extracts daily data","type":"output_rows","condition":"@debug","config":{"data":[{"expression":"@df"}],"writer":{"method":"to_csv","file":"df.csv"}}},{"description":"Extracts all transactions","type":"output_values","condition":"@debug","config":{"writer":{"method":"to_csv","file":"cf.csv"}}},{"description":"Extracts periodic data from data frame based on configuration","type":"output_rows","context":[{"name":"grouped_df","expression":"@df.groupby([@df.Date + pd.offsets.MonthEnd(0), @df.Note])"},{"name":"aggregate_functions","value":{"Date":"last","Note":"first","initbal":"first","funding":"sum","paydown":"sum","schprin":"sum","periodpikint":"sum","act_periodint":"sum","act_periodpikintpaid":"sum","act_periodpikint":"sum","act_pikprinpaid":"sum","endbal":"last","clean_cost":"last","feeamort":"last","cum_am_fee":"last","am_capcosts":"last","am_disc":"last","gaapbv":"last"}}],"config":{"data":[{"expression":"@grouped_df.agg(@aggregate_functions)"}],"writer":{"method":"to_csv","file":"periodic.csv"}}},{"description":"Extracts specific transactions from data frame based on configuration","type":"output_values","config":{"filter":"(@cf.value != 0) & (@cf.Note == @root_note_id)","transactions":[],"writer":{"method":"to_csv","file":"transactions.csv","settings":{"index":"False"}}}},{"description":"Extracts Strips","type":"output_values","config":{"filter":"(@cf.value != 0) & (@cf.Note != @root_note_id)","transactions":[],"writer":{"method":"to_csv","file":"strips.csv","settings":{"index":"False"}}}}]', N'non_BalanceAware', N'request_rules_no_payrules.json', 1)
INSERT [CRE].[JsonTemplate] ([Id], [Key], [Value], [Type], [FileName], [JsonTemplateMasterID]) VALUES (4, N'config', N'{"amsch":{"type":1,"identifier":"dt"},"funding":{"type":1,"identifier":"dt"},"spread":{"type":1,"identifier":"startdt"},"rate":{"type":1,"identifier":"startdt"},"index_floor":{"type":1,"identifier":"startdt"},"amort_spread":{"type":1,"identifier":"startdt"},"amort_rate":{"type":1,"identifier":"startdt"},"amort_index_floor":{"type":1,"identifier":"startdt"},"index_cap":{"type":1,"identifier":"startdt"},"coupon_floor":{"type":1,"identifier":"startdt"},"coupon_cap":{"type":1,"identifier":"startdt"},"pik_rate":{"type":2,"start_identifier":"startdt","end_identifier":"enddt"},"fee":{"type":2,"start_identifier":"startdt","end_identifier":"enddt","config":{"ACORE Orig Fee":{"type":"Origination Fee","frequency":"Transaction Based","accounts":["initbal"]},"Additional Fee":{"type":"Additional Fee","frequency":"Transaction Based","accounts":["endbal"]},"Draw Fee":{"type":"Draw Fee","frequency":"Transaction Based","accounts":["endbal"]},"Exit Fee":{"type":"Exit Fee"},"Exit Fee_IncAmor":{"type":"Exit Fee"},"Exit Fee_Payoff":{"type":"Exit Fee"},"Extension Fee_COMM":{"type":"Extension Fee","frequency":"Transaction Based","accounts":["totalcmt"]},"Extension Fee_UPB":{"type":"Extension Fee","frequency":"Transaction Based","accounts":["endbal"]},"Origination Fee":{"type":"Origination Fee","frequency":"Transaction Based","accounts":["totalcmt"]},"Origination Fee_AsFunded":{"type":"Origination Fee"}}}}', N'V1Calc', N'request_rules_no_payrules.json', 1)
INSERT [CRE].[JsonTemplate] ([Id], [Key], [Value], [Type], [FileName], [JsonTemplateMasterID]) VALUES (5, N'rules', N'[{"description":"Attach a rule which should be executed when an account is updated","type":"attach_rules_to_accounts","config":{"paydown":[{"description":"Calculate Exit Fee","type":"foreach","condition":"(@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee'', ''Exit Fee_IncAmor'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@fee.type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[-@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl"]}}}]}}],"fee_stripped":[{"description":"Calculate Fee Stripping","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee_stripping'']))","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_stripping","rules":[{"description":"Add StripReceivable transactions","type":"add_cashflow","config":{"Date":"@date","Note":"@strip.to","type":"@fee_type","expression":"@amount * @strip.pct","addl_columns":{"Fee Name":"@fee_name","Effective Date":"@effective_date","Parent Note":"@root_note_id"}}}]}}]}},{"description":"For each effective date, execute the following rules","type":"foreach","config":{"foreach_variable_name":"effective_date","expression":"@effective_dates","rules":[{"description":"Delete data for dates greater than effective date","type":"reset","config":{"df":"@df.Date >= pd.Timestamp(@effective_date)","cf":"(@cf.Date >= pd.Timestamp(@effective_date)) & (@cf.Note == @root_note_id)"}},{"description":"Setup note context for effective date","context":[{"name":"note","expression":"@notes[@root_note_id]"},{"name":"is_legal_note","expression":"@note.type == ''legal''"},{"name":"is_closed_note","expression":"@if_exists(@note, [@effective_date], [])"},{"name":"is_closing_effective_date","expression":"@is_closed_note & (pd.Timestamp(@note[@effective_date].clsdt) == pd.Timestamp(@effective_date))"}]},{"description":"Add Initial Funding transaction","type":"add_cashflow","condition":"@is_closing_effective_date","config":{"Date":"pd.Timestamp(@note[@effective_date].clsdt)","Note":"@note.id","type":"InitialFunding","expression":"@note[@effective_date].initbal"}},{"description":"Read values from note setup","type":"read_dict","condition":"@is_closed_note","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","expression":"@note[@effective_date]"}},{"description":"Read records from tables in note setup - Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''rate'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"rate","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].rate","''startdt''"]}}},{"description":"Read records from tables in note setup - Spread","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''spread'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"spread","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].spread","''startdt''"]}}},{"description":"Read records from tables in note setup - Index Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''index_floor'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"index_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].index_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - Index Cap","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''index_cap'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"index_cap","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].index_cap","''startdt''"]}}},{"description":"Read records from tables in note setup - Coupon Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''coupon_floor'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"coupon_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].coupon_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - Amort Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''amort_rate'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"amort_rate","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].amort_rate","''startdt''"]}}},{"description":"Read records from tables in note setup - PIK Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''pikrate'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","table":"pikrate","function":{"name":"get_pikrates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].pikrate","''startdt''","''enddt''"]}}},{"description":"Allocate Fundings to the notes","type":"pay","ignoreerror":"False","condition":"@if_exists(@note, [@effective_date], [''funding''])","config":{"source":"[x for x in @note[@effective_date].funding if x.fundpydn > 0 and pd.Timestamp(x.dt) >= pd.Timestamp(@effective_date)]","amount_col":"fundpydn","date_col":"dt","account":"funding","rules":[{"description":"Pay everything to the note","config":{"note":"@note.id","weight":1}}]}},{"description":"Allocate Paydowns to the notes","type":"pay","ignoreerror":"False","condition":"@if_exists(@note, [@effective_date], [''funding''])","config":{"source":"[x for x in @note[@effective_date].funding if x.fundpydn < 0 and pd.Timestamp(x.dt) >= pd.Timestamp(@effective_date)]","amount_col":"fundpydn","date_col":"dt","account":"paydown","rules":[{"description":"Pay everything to the note","config":{"note":"@note.id","weight":1}}]}},{"description":"Assign strip receivables","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''fee_strip_received''])","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_strip_received","rules":[{"description":"Assign strip to the note","type":"accumulate","context":[{"name":"fee_type","expression":"@strip.type"},{"name":"fee_name","expression":"@strip.feename"}],"config":{"filter":"@df.Date == pd.Timestamp(@strip.dt)","columns":["fee_strip_received"],"expression":"@strip.val"}}]}},{"description":"Identify accrual end dates","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initaccenddt'',''initmatdt'', ''leaddays'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["periodstart","periodend","pmtdt","term","indexrefdt"],"function":{"name":"get_accrual_dates","module":"dates","package":"m61_finance.cre","parameters":["@df.Date","@df.clsdt[0]","@df.initaccenddt[0]","pd.Timestamp(@period_end_date)","@df.initpmtdt[0]","[pd.Timestamp(dt) for dt in @calendar[''US'']]","@df.leaddays[0]","@df.perenddtbuslag[0]","@df.paydatebusiessdaylag[0]"]}}},{"description":"Identify io term end date","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initpmtdt'',''ioterm'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["io_term_end_date"],"expression":"@df.initpmtdt[0] + pd.DateOffset(months=@df.ioterm[0] - 1)"}},{"description":"Read actuals - Payment date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''periodpikintpaid'', ''periodint'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.pmtdt == pd.Timestamp(@actual.dt)) & (@df.Date == @df.periodend)","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Read actuals - Transaction date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''pikprinpaid'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.Date == pd.Timestamp(@actual.dt))","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Calculate Schedule Principal - Debt Service Override","type":"assignment","condition":"@note[@effective_date].monamovrd > 0","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date)) & (@df.term > 0) & (@df.Date == @df.periodend) & (@df.Date < @df.initmatdt)","columns":["schprin"],"expression":"@df.monamovrd"}},{"description":"Calculate Schedule Principal - Amort Schedule","type":"foreach","condition":"(@note[@effective_date].monamovrd == 0) & (@if_exists(@note, [@effective_date], [''amsch'']))","config":{"foreach_var