INSERT [CRE].[JsonTemplate] ([Id], [Key], [Value], [Type], [FileName], [JsonTemplateMasterID]) VALUES (7, N'rules', N'[{"description":"Attach a rule which should be executed when an account is updated","type":"attach_rules_to_accounts","config":{"funding":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''ACORE Orig Fee'', ''Origination Fee_AsFunded'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"paydown":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee'', ''Exit Fee_IncAmor'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[-@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"schprin":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee_IncAmor'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"balloon":[{"description":"Calculate Fee","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee'']))","config":{"foreach_variable_name":"fee","expression":"[x for x in @note[@effective_date].fee if x.type in [''Exit Fee'', ''Exit Fee_IncAmor'', ''Exit Fee_Payoff'']]","rules":[{"description":"Fee","type":"accumulate","condition":"pd.Timestamp(@fee.startdt) <= @date <= pd.Timestamp(@fee.enddt)","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"}],"config":{"filter":"(@df.Date == @date)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["[@amount]","@fee.ovrbaseamt","@fee.ovrfeeamt","@fee.val","@fee.stripval","@fee.levyldincl","@fee.trueupflag == ''571''"]}}}]}}],"fee_stripped":[{"description":"Add Fee stripping included in level yield transaction","type":"add_cashflow","condition":"(@amount != 0)","config":{"Date":"@date","Note":"@note.id","type":"@fee_type.replace('' '', '''') + ''Stripping''","expression":"-@amount * @fee.levyldincl","addl_columns":{"Fee Name":"@fee_name"}}},{"description":"Add Fee stripping excluded from level yield transaction","type":"add_cashflow","condition":"(@amount != 0)","config":{"Date":"@date","Note":"@note.id","type":"@fee_type.replace('' '', '''') + ''StrippingExcldfromLevelYield''","expression":"-@amount * (1 - @fee.levyldincl)","addl_columns":{"Fee Name":"@fee_name"}}},{"description":"Calculate Fee Stripping","type":"foreach","condition":"(@amount != 0) & (@if_exists(@note, [@effective_date], [''fee_stripping'']))","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_stripping","rules":[{"description":"Add StripReceivable transactions","type":"add_cashflow","config":{"Date":"@date","Note":"@strip.to","type":"@fee_type","expression":"@amount * @strip.pct","addl_columns":{"Fee Name":"@fee_name","Effective Date":"@effective_date","Parent Note":"@root_note_id"}}}]}}],"pmtdtpikint":[{"description":"Update balances if pik interest for prior day is updated","type":"foreach","condition":"(@amount != 0) & @update_balances & (@row[''pmtdt''] < @row[''periodend''])","config":{"foreach_variable_name":"date","expression":"pd.date_range(@row[''pmtdt''], @row[''periodend''], closed=''left'')","rules":[{"description":"Update ending balance","type":"accumulate","config":{"filter":"@df.Date == @date","columns":["endbal"],"expression":"@amount"}},{"description":"Update next day''s beginning balance","type":"accumulate","config":{"filter":"@df.Date == (pd.Timestamp(@date) + pd.DateOffset())","columns":["initbal"],"expression":"@amount"}}]}}]}},{"description":"For each effective date, execute the following rules","type":"foreach","config":{"foreach_variable_name":"effective_date","expression":"[x for x in @effective_dates if pd.Timestamp(x) <= pd.Timestamp(@period_end_date)]","rules":[{"description":"Setup context for effective date","context":[{"name":"note","expression":"@notes[@root_note_id]"},{"name":"is_legal_note","expression":"@note.type == ''legal''"},{"name":"is_closed_note","expression":"@if_exists(@note, [@effective_date], [])"},{"name":"is_closing_effective_date","expression":"@is_closed_note & (pd.Timestamp(@note[@effective_date].clsdt) == pd.Timestamp(@effective_date))"},{"name":"loop_until","expression":"@period_end_date"},{"name":"dates_in_current_schedule","expression":"pd.date_range(@effective_date, @loop_until)"},{"name":"date_filter","expression":"@df.Date.isin(@dates_in_current_schedule)"},{"name":"loanterm","expression":"(pd.Timestamp(@note[@effective_date].initmatdt).year - pd.Timestamp(@note[@effective_date].clsdt).year)*12 + (pd.Timestamp(@note[@effective_date].initmatdt).month - pd.Timestamp(@note[@effective_date].clsdt).month)"},{"name":"update_balances","value":false}]},{"description":"Delete data for dates greater than effective date","type":"reset","config":{"df":"@df.Date >= pd.Timestamp(@effective_date)","cf":"(@cf.Date >= pd.Timestamp(@effective_date)) & (@cf.Note == @root_note_id)"}},{"description":"Set the Effective Date Column","type":"assignment","condition":"@is_closed_note","config":{"filter":"(@date_filter)","columns":["effectivedate"],"expression":"@effective_date"}},{"description":"Set the Loan Term based on Current Maturity","type":"assignment","condition":"@is_closed_note","config":{"filter":"(@date_filter)","columns":["loanterm"],"expression":"(pd.Timestamp(@note[@effective_date].initmatdt).year - pd.Timestamp(@note[@effective_date].clsdt).year)*12 + (pd.Timestamp(@note[@effective_date].initmatdt).month - pd.Timestamp(@note[@effective_date].clsdt).month)"}},{"description":"Add Initial Funding transaction","type":"add_cashflow","condition":"@is_closing_effective_date","config":{"Date":"pd.Timestamp(@note[@effective_date].clsdt)","Note":"@note.id","type":"InitialFunding","expression":"-@note[@effective_date].initbal"}},{"description":"Read values from note setup","type":"read_dict","condition":"@is_closed_note","config":{"filter":"(@date_filter)","expression":"@note[@effective_date]"}},{"description":"Read records from tables in note setup - Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''rate'']))","config":{"filter":"(@date_filter)","table":"rate","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].rate","''startdt''"]}}},{"description":"Read records from tables in note setup - Spread","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''spread'']))","config":{"filter":"(@date_filter)","table":"spread","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].spread","''startdt''"]}}},{"description":"Read records from tables in note setup - Index Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''index_floor'']))","config":{"filter":"(@date_filter)","table":"index_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].index_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - Index Cap","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''index_cap'']))","config":{"filter":"(@date_filter)","table":"index_cap","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].index_cap","''startdt''"]}}},{"description":"Read records from tables in note setup - Coupon Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''coupon_floor'']))","config":{"filter":"(@date_filter)","table":"coupon_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].coupon_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - Amort Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''amort_rate'']))","config":{"filter":"(@date_filter)","table":"amort_rate","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].amort_rate","''startdt''"]}}},{"description":"Read records from tables in note setup - Amort Spread","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''amort_spread'']))","config":{"filter":"(@date_filter)","table":"amort_spread","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].amort_spread","''startdt''"]}}},{"description":"Read records from tables in note setup - Amort Floor","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''amort_index_floor'']))","config":{"filter":"(@date_filter)","table":"amort_index_floor","function":{"name":"get_rates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].amort_index_floor","''startdt''"]}}},{"description":"Read records from tables in note setup - PIK Rate","type":"read_records","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''pikrate'']))","config":{"filter":"(@date_filter)","table":"pikrate","function":{"name":"get_pikrates","module":"rates","package":"m61_finance.cre","parameters":["@df.Date","@note[@effective_date].pikrate","''startdt''","''enddt''"]}}},{"description":"Get Holiday Adjusted Maturity Date","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initmatdt'']))","config":{"filter":"(@date_filter)","columns":["initmatdt"],"function":{"name":"get_holiday_adjusted_dates","module":"dates","package":"m61_finance.cre","parameters":["@df.initmatdt[0]","[pd.Timestamp(dt) for dt in @calendar[''US'']]","@df.paydatebusiessdaylag[0]"]}}},{"description":"Set beginning balance from prior period ending balance","type":"assignment","condition":"not @is_closing_effective_date","context":[{"name":"ending_balance","expression":"@df[@df.Date == pd.Timestamp(@effective_date) - pd.DateOffset()].endbal"}],"config":{"filter":"@df.Date == pd.Timestamp(@effective_date)","columns":["initbal"],"expression":"@ending_balance.to_numpy()"}},{"description":"Allocate Fundings to the notes","type":"pay","ignoreerror":"False","condition":"@if_exists(@note, [@effective_date], [''funding''])","config":{"source":"[x for x in @note[@effective_date].funding if x.fundpydn > 0 and pd.Timestamp(@effective_date) <= pd.Timestamp(x.dt) < pd.Timestamp(@loop_until) and pd.Timestamp(x.dt) <= pd.Timestamp(@note[@effective_date].initmatdt)]","amount_col":"fundpydn","date_col":"dt","account":"funding","rules":[{"description":"Pay everything to the note","config":{"note":"@note.id","weight":1}}]}},{"description":"Allocate Paydowns to the notes","type":"pay","ignoreerror":"False","condition":"@if_exists(@note, [@effective_date], [''funding''])","config":{"source":"[x for x in @note[@effective_date].funding if x.fundpydn < 0 and pd.Timestamp(@effective_date) <= pd.Timestamp(x.dt) < pd.Timestamp(@loop_until)]","amount_col":"fundpydn","date_col":"dt","account":"paydown","rules":[{"description":"Pay everything to the note","config":{"note":"@note.id","weight":1}}]}},{"description":"Assign strip receivables","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''fee_strip_received''])","config":{"foreach_variable_name":"strip","expression":"@note[@effective_date].fee_strip_received","rules":[{"description":"Assign strip to the note","type":"accumulate","context":[{"name":"fee_type","expression":"@strip.type"},{"name":"fee_name","expression":"@strip.feename"}],"config":{"filter":"@df.Date == pd.Timestamp(@strip.dt)","columns":["fee_strip_received"],"expression":"@strip.val"}}]}},{"description":"Identify accrual end dates","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initaccenddt'',''initmatdt'', ''leaddays'']))","config":{"filter":"(@df.Date >= pd.Timestamp(@effective_date))","columns":["periodstart","periodend","pmtdt","term","indexrefdt"],"function":{"name":"get_accrual_dates","module":"dates","package":"m61_finance.cre","parameters":["@df.Date","@df.clsdt[0]","@df.initaccenddt[0]","pd.Timestamp(@period_end_date)","@df.initaccenddt[0] + pd.offsets.DateOffset()","[pd.Timestamp(dt) for dt in @calendar[''US'']]","@df.leaddays[0]","@df.perenddtbuslag[0]","@df.paydatebusiessdaylag[0]","@note[@effective_date].accfreq"]}}},{"description":"Identify io term end date","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_exists(@note, [@effective_date], [''initpmtdt'',''ioterm'']))","context":[{"name":"adjustment","expression":"1 if @note[@effective_date].stubpaidadv==''N'' else 0"}],"config":{"filter":"(@date_filter)","columns":["io_term_end_date"],"expression":"@df.clsdt if @note[@effective_date].ioterm == 0  else @df.initaccenddt[0] + pd.DateOffset(months=@df.ioterm[0] + @adjustment)"}},{"description":"Read actuals - Payment date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''periodpikintpaid'', ''periodint'', ''periodpikint'']]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@date_filter) & (@df.term > 0) & (@df.pmtdt == pd.Timestamp(@actual.dt)) & (@df.Date == @df.periodend)","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Read actuals - Transaction date","type":"foreach","condition":"@if_exists(@note, [@effective_date], [''actuals''])","config":{"foreach_variable_name":"actual","expression":"[x for x in @note[@effective_date].actuals if x.account in [''pikprinpaid''] and pd.Timestamp(@effective_date) <= pd.Timestamp(x.dt) < pd.Timestamp(@loop_until)]","rules":[{"description":"Assign actuals to df","type":"accumulate","config":{"filter":"(@date_filter) & (@df.Date == pd.Timestamp(@actual.dt))","columns":"[''act_'' + @actual.account]","expression":"@actual.val"}}]}},{"description":"Calculate Accrual Period PIK Interest - Use override from actuals","type":"assignment","config":{"filter":"(@date_filter) & (@df.act_periodpikint > 0)","columns":["periodpikint"],"expression":"@df.act_periodpikint - @df.act_periodpikintpaid"}},{"description":"Calculate Scheduled Principal - Debt Service Override","type":"assignment","condition":"@note[@effective_date].monamovrd > 0","config":{"filter":"(@date_filter) & (@df.Date > @df.io_term_end_date) & (@df.Date.isin(@df.pmtdt)) & (@df.Date >= @df.initaccenddt) & (@df.Date < @df.initmatdt)","columns":["schprin"],"expression":"@df.monamovrd.apply(str).apply(Decimal)","assign_to":"(@date_filter) & (@df.Date > @df.io_term_end_date) & (@df.Date.isin(@df.pmtdt)) & (@df.Date >= @df.initaccenddt) & (@df.Date < @df.initmatdt)"}},{"description":"Calculate Scheduled Principal - Amort Schedule","type":"foreach","condition":"(@note[@effective_date].monamovrd == 0) & (@if_exists(@note, [@effective_date], [''amsch'']))","config":{"foreach_variable_name":"amort","expression":"@note[@effective_date].amsch","rules":[{"description":"Assign amort to df","type":"accumulate","config":{"filter":"(@date_filter) & (@df.Date > @df.io_term_end_date) & (@df.Date == pd.Timestamp(@amort.dt)) & (@df.Date >= @df.initaccenddt) & (@df.Date < @df.initmatdt)","columns":["schprin"],"expression":"Decimal(@amort.val)"}}]}},{"description":"Set Discount/Premium - Initialize","type":"assignment","condition":"@is_legal_note & @is_closed_note & (@if_e