ty date","type":"accumulate","context":[{"name":"fee_type","expression":"@config.fee.config[@fee.type].type"},{"name":"fee_name","expression":"@fee.feename"},{"name":"total_paydowns","expression":"@df.paydown.sum()"}],"config":{"filter":"(@df.Date == @df.initmatdt)","columns":["fee_amount","fee_stripped","fee_incl_lv_yield","fee_excl_lv_yield"],"function":{"name":"get_fee","module":"fees","package":"m61_finance.cre","parameters":["@fee.ovrbaseamt + @total_paydowns - @df.balloon",null,null,"@fee.val","@fee.stripval","@fee.levyldincl",false]}}}]}},{"description":"Calculate Gross Deferred Fee for the Effective Date","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["gross_def_fees"],"expression":"@df.fee_incl_lv_yield.sum()"}},{"description":"Calculate Clean Cost","type":"assignment","config":{"filter":"@df.Date >= pd.Timestamp(@effective_date)","columns":["clean_cost"],"expression":"@df.endbal - @df.gross_def_fees + @df.discount  + @df.capcosts"}},{"description":"For each note, execute the basis rules","type":"foreach","config":{"foreach_variable_name":"note","expression":"@notes.values()","rules":[{"description":"Calculate Level Yield - Deferred Fee Yield","type":"assignment","condition":"@calc_deffee_basis & @is_legal_note & @is_closed_note","context":[{"name":"prev_gaapbasis","expression":"-@df.at[(pd.Timestamp(@effective_date), @note.id), ''initbal''] if @is_closing_effective_date else -@df.at[(pd.Timestamp(@effective_date) - pd.DateOffset(), @note.id), ''gaapbasis'']"}],"config":{"filter":"(@date_filter)","columns":["levyld"],"function":{"name":"calculate_level_yield","module":"basis","package":"m61_finance.cre","parameters":["@df.Date","@df.initbal - @df.endbal + @df.fee_incl_lv_yield","pd.Timestamp(@effective_date) if @is_closing_effective_date else (pd.Timestamp(@effective_date) - pd.DateOffset())","@prev_gaapbasis"]}}},{"description":"Calculate Level Yield - Copy to deffeeyld","type":"assignment","config":{"filter":